import { useState } from "react";
import { useNavigate } from "react-router-dom";

function Home(){

    const navigate = useNavigate();

    const [courses,setCourses] = useState([]);


    const scholarshipData = {

        Government:[
            "UPSC",
            "SSC",
            "Banking"
        ],

        Engineering:[
            "B.Tech",
            "M.Tech",
            "Diploma"
        ],

        Medical:[
            "MBBS",
            "Nursing",
            "Pharmacy"
        ],

        Computer:[
            "BCA",
            "MCA",
            "BSc IT"
        ]

    };


    const showCourses = (category)=>{

        setCourses(scholarshipData[category]);

    }


    const applyCourse = (course)=>{

        navigate("/apply",{
            state:{course}
        });

    }


    return(

        <div className="container">

            <h2>Scholarship Categories</h2>

            <div className="card-container">

                <div
                className="card"
                onClick={()=>showCourses("Government")}
                >
                    Government
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Engineering")}
                >
                    Engineering
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Medical")}
                >
                    Medical
                </div>

                <div
                className="card"
                onClick={()=>showCourses("Computer")}
                >
                    Computer
                </div>

            </div>


            <h3>Available Courses</h3>

            {
                courses.map((item,index)=>(

                    <button
                    key={index}
                    onClick={()=>applyCourse(item)}
                    >
                        {item}
                    </button>

                ))
            }

        </div>

    )

}

export default Home;
